#include <iostream>
#include <vector>
#include <string>
#include <algorithm>  // For std::reverse

using namespace std;

bool is_safe(const vector<string>& board, int row, int col, int n) {
    // Check if there is a queen in the same column
    for (int i = 0; i < row; ++i) {
        if (board[i][col] == 'Q') {
            return false;
        }
    }

    // Check if there is a queen in the left diagonal
    for (int i = row, j = col; i >= 0 && j >= 0; --i, --j) {
        if (board[i][j] == 'Q') {
            return false;
        }
    }

    // Check if there is a queen in the right diagonal
    for (int i = row, j = col; i >= 0 && j < n; --i, ++j) {
        if (board[i][j] == 'Q') {
            return false;
        }
    }

    return true;
}

void solve_n_queens_util(vector<string>& board, int row, int n, vector<vector<string>>& result) {
    if (row == n) {
        result.push_back(board);
        return;
    }

    for (int col = 0; col < n; ++col) {
        if (is_safe(board, row, col, n)) {
            board[row][col] = 'Q';
            solve_n_queens_util(board, row + 1, n, result);
            board[row][col] = '.';  // Backtrack
        }
    }
}

vector<vector<string>> solve_n_queens(int n) {
    vector<string> board(n, string(n, '.'));
    vector<vector<string>> result;
    solve_n_queens_util(board, 0, n, result);
    return result;
}

int main() {
    int n;
    cin >> n;
    vector<vector<string>> solutions = solve_n_queens(n);
    reverse(solutions.begin(), solutions.end());
    for (const auto& solution : solutions) {
        for (const auto& row : solution) {
            cout << row << endl;
        }
        cout << endl;
    }
    return 0;
}

