#include <stdio.h>
#include <stdbool.h>
#include <stdlib.h>
#include <string.h>

// Function to check if placing a queen at board[row][col] is safe
bool is_safe(char **board, int row, int col, int n) {
    for (int i = 0; i < row; ++i) {
        if (board[i][col] == 'Q') {
            return false;
        }
    }

    for (int i = row, j = col; i >= 0 && j >= 0; --i, --j) {
        if (board[i][j] == 'Q') {
            return false;
        }
    }

    for (int i = row, j = col; i >= 0 && j < n; --i, ++j) {
        if (board[i][j] == 'Q') {
            return false;
        }
    }

    return true;
}

// Utility function for solving N-Queens using backtracking
void solve_n_queens_util(char **board, int row, int n, char ***result, int *result_size) {
    if (row == n) {
        result[*result_size] = malloc(n * sizeof(char *));
        for (int i = 0; i < n; ++i) {
            result[*result_size][i] = strdup(board[i]);
        }
        (*result_size)++;
        return;
    }

    for (int col = 0; col < n; ++col) {
        if (is_safe(board, row, col, n)) {
            board[row][col] = 'Q';
            solve_n_queens_util(board, row + 1, n, result, result_size);
            board[row][col] = '.';  // Backtrack
        }
    }
}

// Function to solve N-Queens problem and return all solutions
char ***solve_n_queens(int n, int *return_size) {
    char **board = malloc(n * sizeof(char *));
    for (int i = 0; i < n; ++i) {
        board[i] = malloc((n + 1) * sizeof(char));
        memset(board[i], '.', n);
        board[i][n] = '\0';
    }

    int max_solutions = 1000; // assuming a maximum of 1000 solutions
    char ***result = malloc(max_solutions * sizeof(char **));
    *return_size = 0;

    solve_n_queens_util(board, 0, n, result, return_size);

    for (int i = 0; i < n; ++i) {
        free(board[i]);
    }
    free(board);

    return result;
}

// Function to free the allocated memory for the results
void free_results(char ***result, int result_size, int n) {
    for (int i = 0; i < result_size; ++i) {
        for (int j = 0; j < n; ++j) {
            free(result[i][j]);
        }
        free(result[i]);
    }
    free(result);
}

int main() {
    int n;
    scanf("%d", &n);

    int return_size;
    char ***solutions = solve_n_queens(n, &return_size);

    // Print solutions in reverse order to match the required output format
    for (int i = return_size - 1; i >= 0; --i) {
        for (int j = 0; j < n; ++j) {
            printf("%s\n", solutions[i][j]);
        }
        printf("\n");
    }

    free_results(solutions, return_size, n);

    return 0;
}

