import java.util.*;

class main {

    static int[] dx = {0, 0, -1, -1, -1, 1, 1, 1};
    static int[] dy = {-1, 1, 0, -1, 1, 0, -1, 1};

    static boolean check(List<String> board, int n, int row, int col) {
        for (int k = 0; k < 8; k++) {
            int x = row, y = col;
            while (x >= 0 && x < n && y >= 0 && y < n) {
                if (board.get(x).charAt(y) == 'Q') {
                    return false; // Queen attacks another
                }
                x += dx[k];
                y += dy[k];
            }
        }
        return true; // Can place queen here
    }

    static void backtrack(int row, int n, List<String> board, List<List<String>> ans) {
        if (row == n) { // No more rows to fill
            ans.add(new ArrayList<>(board));  // Add the possible answer
            return;
        }
        for (int col = 0; col < n; col++) {
            if (check(board, n, row, col)) {
                StringBuilder sb = new StringBuilder(board.get(row));
                sb.setCharAt(col, 'Q'); // Add the queen
                board.set(row, sb.toString());
                backtrack(row + 1, n, board, ans);
                sb.setCharAt(col, '.'); // Remove the queen
                board.set(row, sb.toString());
            }
        }
    }

    static List<List<String>> nQueens(int n) {
        List<String> board = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            StringBuilder sb = new StringBuilder();
            for (int j = 0; j < n; j++) {
                sb.append('.');
            }
            board.add(sb.toString());
        }

        List<List<String>> ans = new ArrayList<>();
        backtrack(0, n, board, ans);
        return ans;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        List<List<String>> a = nQueens(n);
        Collections.sort(a, (x, y) -> {
            for (int i = 0; i < n; i++) {
                int cmp = x.get(i).compareTo(y.get(i));
                if (cmp != 0) return cmp;
            }
            return 0;
        });

        for (List<String> board : a) {
            for (String row : board) {
                System.out.println(row);
            }
            System.out.println();
        }
    }
}
